INSERT INTO `photographer_profiles` VALUES (1,3,'3 роки досвіду','Працює з портретними, fashion і creative-проєктами. Підходить для клієнтів, яким потрібен виразний, стилізований і візуально сильний результат.','https://i.pinimg.com/736x/23/0f/a8/230fa844785e0ce8699caaf8231595d1.jpg',5,1,'2026-05-13 10:24:36'),(2,5,'5 років досвіду','Працює з індивідуальними та портретними зйомками у студії. Допомагає створити виразний, чистий і сучасний візуальний результат.','https://i.pinimg.com/1200x/af/61/e0/af61e09e6e9635c300f1e7a091c87d8b.jpg',0,1,'2026-05-13 10:24:36'),(3,6,'6 років досвіду','Спеціалізується на сімейних і дитячих зйомках. У кадрі зберігає природність, емоційність і комфорт для всієї родини.','https://i.pinimg.com/1200x/5b/0e/34/5b0e34f51a9b8f9cc91c5e39df5807db.jpg',1,1,'2026-05-13 10:24:36'),(4,7,'7 років досвіду','Працює з весільними історіями, парними фотосесіями та Love Story. Акцент на композиції, емоціях і цілісній візуальній подачі.','https://i.pinimg.com/736x/7d/6c/44/7d6c4441920d1c8e24b2060fdea4fbba.jpg',2,1,'2026-05-13 10:24:36'),(5,8,'5 років досвіду','Проводить делікатні та акуратні зйомки для майбутніх мам і новонароджених. Працює у спокійному форматі з увагою до деталей і безпеки.','https://i.pinimg.com/1200x/ff/85/59/ff85593532c862d04f608d160ac22ce6.jpg',3,1,'2026-05-13 10:24:36'),(6,9,'3 роки досвіду','Працює з брендовим, рекламним і комерційним контентом. Створює матеріали для соцмереж, сайтів, кампаній і digital-комунікації.','https://i.pinimg.com/736x/68/bb/45/68bb45005df3f24cff8240f73a2f4932.jpg',4,1,'2026-05-13 10:24:36'),(7,10,'2 роки досвіду','Спеціалізується на репортажних і виїзних зйомках. Добре працює з подіями, динамікою кадру та живими моментами.','https://i.pinimg.com/1200x/eb/14/9f/eb149fb341d97cd0ffa6b0a4c30cd297.jpg',6,1,'2026-05-13 10:24:36'),(8,11,'4 роки досвіду','Займається предметною та каталожною зйомкою для бізнесу, брендів і маркетплейсів. Формує чистий комерційний кадр із фокусом на продукт.','https://i.pinimg.com/736x/fb/86/6d/fb866d85261dde037298d9038910ecf4.jpg',7,1,'2026-05-13 10:24:36'),(31,24,'2 роки досвіду',NULL,'https://i.pinimg.com/1200x/32/f1/45/32f14545dd814249c8d00519b6c8a1ff.jpg',0,0,'2026-05-23 13:48:57');
/*!40000 ALTER TABLE `photographer_profiles` ENABLE KEYS */;
